export function attachIsolateDocs(
  docs: NearbyDoc[],
  communities: CommunityClaim[],
): AttachmentResult {
  const byCommunityId = new Map<string, NearbyDoc[]>();
  for (const c of communities) byCommunityId.set(c.communityId, []);
  const unmatched: NearbyDoc[] = [];

  for (const doc of docs) {
    let best: { community: CommunityClaim; depth: number } | null = null;
    for (const c of communities) {
      let maxDepth = 0;
      for (const f of c.memberFiles) {
        const d = sharedPrefixDepth(doc.path, f);
        if (d > maxDepth) maxDepth = d;
      }
      if (maxDepth < MIN_SHARED_SEGMENTS) continue;
      if (
        !best ||
        maxDepth > best.depth ||
        (maxDepth === best.depth && c.memberFiles.length > best.community.memberFiles.length)
      ) {
        best = { community: c, depth: maxDepth };
      }
    }

    if (!best) {
      unmatched.push(doc);
      continue;
    }
    const cap =
      best.community.cohesion < LOW_COHESION_THRESHOLD
        ? MAX_DOCS_LOW_COHESION
        : MAX_DOCS_HIGH_COHESION;
    const list = byCommunityId.get(best.community.communityId)!;
    if (list.length < cap) {
      list.push(doc);
    } else {
      unmatched.push(doc);
    }
  }

  return { byCommunityId, unmatched };
}

export async function benchmarkCommand(args: string[], getFlag: (flag: string) => string | undefined) {
  const file = args[1];
  if (!file) {
    cli.error("Usage: mimirs benchmark <file> [--dir D] [--top N]");
    process.exit(1);
  }

  const dir = resolve(getFlag("--dir") || ".");
  const db = new RagDB(dir);
  const config = await loadConfig(dir);
  const top = parseInt(getFlag("--top") || String(config.benchmarkTopK), 10);

  const queries = await loadBenchmarkQueries(resolve(file));
  cli.log(`Running ${queries.length} benchmark queries against ${dir}...\n`);

  const summary = await runBenchmark(queries, db, dir, top);
  cli.log(formatBenchmarkReport(summary, top));

  db.close();

  // Exit with non-zero if below thresholds
  if (summary.recallAtK < config.benchmarkMinRecall || summary.mrr < config.benchmarkMinMrr) {
    process.exit(1);
  }
}

export async function benchmarkModelsCommand(args: string[], getFlag: (flag: string) => string | undefined) {
  const file = args[1];
  if (!file) {
    cli.error("Usage: mimirs benchmark-models <queries.json> --models model1,model2 [--dir D] [--top N]");
    cli.error("\nKnown models:");
    for (const [name, spec] of Object.entries(KNOWN_MODELS)) {
      cli.error(`  ${name} (${spec.dim}d)`);
    }
    process.exit(1);
  }

  const dir = resolve(getFlag("--dir") || ".");
  const config = await loadConfig(dir);
  const top = parseInt(getFlag("--top") || String(config.benchmarkTopK), 10);
  const modelsArg = getFlag("--models");

  if (!modelsArg) {
    cli.error("Error: --models is required. Example: --models Xenova/all-MiniLM-L6-v2,Xenova/bge-small-en-v1.5");
    process.exit(1);
  }

  const models = modelsArg.split(",").map(parseModelArg);
  const queries = await loadBenchmarkQueries(resolve(file));
  const results: { model: ModelSpec; summary: BenchmarkSummary; indexTimeMs: number }[] = [];

  cli.log(`Comparing ${models.length} models on ${queries.length} queries (top-${top})...\n`);

  for (const model of models) {
    cli.log(`\n--- ${model.id} (${model.dim}d) ---`);

    // Configure the embedder for this model
    configureEmbedder(model.id, model.dim);
    resetEmbedder();

    // Create a temporary DB for this model
    const tmpDir = join(dir, `.rag-eval-${model.id.replace(/\//g, "-")}`);
    if (existsSync(tmpDir)) rmSync(tmpDir, { recursive: true });
    mkdirSync(tmpDir, { recursive: true });

    // Create a temp config pointing at this temp dir
    const tmpRagDir = tmpDir;
    const db = new RagDB(dir, tmpRagDir);

    try {
      // Index
      cli.log("  Indexing...");
      const indexStart = performance.now();
      const indexResult = await indexDirectory(dir, db, config, (msg) => {
        process.stdout.write(`\r  ${msg}`);
      });
      const indexTimeMs = Math.round(performance.now() - indexStart);
      cli.log(`\n  Indexed ${indexResult.indexed} files in ${(indexTimeMs / 1000).toFixed(1)}s`);

      // Benchmark
      cli.log("  Running benchmark...");
      const summary = await runBenchmark(queries, db, dir, top, config.hybridWeight);

      results.push({ model, summary, indexTimeMs });

      cli.log(`  Recall@${top}: ${(summary.recallAtK * 100).toFixed(1)}%`);

export function buildArchitectureBundle(
  discovery: DiscoveryResult,
  classified: ClassifiedInventory,
  syntheses: SynthesesFile,
  bundlesById: Map<string, CommunityBundle>,
  db: RagDB,
  projectDir: string,
  supplementaryDocs: { path: string; content: string }[] = [],
): ArchitectureBundle {
  const communities = Object.values(syntheses.payloads)
    .map((p) => ({
      slug: p.slug,
      name: p.name,
      purpose: p.purpose,
      memberFiles: syntheses.memberSets[p.communityId] ?? [],
    }))
    .sort((a, b) => a.slug.localeCompare(b.slug));

  const fileToCommunity = new Map<string, string>();
  for (const c of communities) {
    for (const f of c.memberFiles) fileToCommunity.set(f, c.slug);
  }

  const metaEdgeWeights = new Map<string, number>();
  for (const edge of discovery.graphData.fileLevel.edges) {
    if (edge.from === edge.to) continue;
    const fromSlug = fileToCommunity.get(edge.from);
    const toSlug = fileToCommunity.get(edge.to);
    if (!fromSlug || !toSlug || fromSlug === toSlug) continue;
    const key = `${fromSlug}\0${toSlug}`;
    metaEdgeWeights.set(key, (metaEdgeWeights.get(key) ?? 0) + 1);
  }
  const metaEdges = [...metaEdgeWeights.entries()]
    .map(([key, weight]) => {
      const [from, to] = key.split("\0");
      return { from, to, weight };
    })
    .sort((a, b) =>
      a.from === b.from ? a.to.localeCompare(b.to) : a.from.localeCompare(b.from),
    );

  const communityPageRank = computeCommunityMetaPageRank(
    communities.map((c) => c.slug),
    metaEdges,
  );

  // For every top hub, derive the set of communities that import it via a
  // file-level edge whose source is outside the hub's own community. The
  // list gives the writer prose-ready phrasing ("imported by 8 of 12
  // communities") instead of a raw fan-in number rendered as trivia.
  const importsByHub = new Map<string, Set<string>>();
  for (const edge of discovery.graphData.fileLevel.edges) {
    if (edge.from === edge.to) continue;
    const fromSlug = fileToCommunity.get(edge.from);
    const toSlug = fileToCommunity.get(edge.to);
    if (!fromSlug || !toSlug || fromSlug === toSlug) continue;
    const set = importsByHub.get(edge.to) ?? new Set<string>();
    set.add(fromSlug);
    importsByHub.set(edge.to, set);
  }

export function buildCommunityBundles(
  db: RagDB,
  discovery: DiscoveryResult,
  classified: ClassifiedInventory,
  projectDir: string,
): BundleBuildResult {
  const communities = flattenModules(discovery.modules);
  const symbolsByFile = new Map<string, ClassifiedSymbol[]>();
  for (const s of classified.symbols) {
    if (!symbolsByFile.has(s.file)) symbolsByFile.set(s.file, []);
    symbolsByFile.get(s.file)!.push(s);
  }

  // Stable community ids derived once so we can thread matched docs through.
  const communityIds = communities.map((c) => communityIdFor([...c.files].sort()));
  const isolateDocs = collectIsolateDocs(discovery.graphData.fileLevel, projectDir);
  const { byCommunityId, unmatched } = attachIsolateDocs(
    isolateDocs,
    communities.map((c, i) => ({
      communityId: communityIds[i],
      memberFiles: c.files,
      cohesion: c.cohesion,
    })),
  );

  // Precompute project-wide DB lookups in batch — one query per kind across
  // every member file in the wiki. Without this, `buildOneBundle` made
  // O(communities × members × 4) round-trips (getFileByPath, getDependsOn,
  // getDependedOnBy, getAnnotations); for 1k-file projects that was the
  // dominant wall-time cost of bundling. With batching it's O(4) plus
  // per-community lookups against the precomputed maps.
  const allMemberPaths = [...new Set(communities.flatMap((c) => c.files))];
  const fileRowsByPath = new Map<string, { id: number; path: string }>();
  for (const f of db.getFilesByPaths(allMemberPaths.map((p) => resolve(projectDir, p)))) {
    fileRowsByPath.set(f.path, f);
  }
  const pathByFileId = new Map<number, string>();
  for (const [, f] of fileRowsByPath) pathByFileId.set(f.id, f.path);
  const allFileIds = [...fileRowsByPath.values()].map((f) => f.id);

  const depsByFromId = new Map<number, string[]>();
  for (const row of db.getDependsOnForFiles(allFileIds)) {
    let arr = depsByFromId.get(row.fromFileId);
    if (!arr) { arr = []; depsByFromId.set(row.fromFileId, arr); }
    arr.push(row.toPath);
  }
  const consumersByToId = new Map<number, string[]>();
  for (const row of db.getDependedOnByForFiles(allFileIds)) {
    let arr = consumersByToId.get(row.toFileId);
    if (!arr) { arr = []; consumersByToId.set(row.toFileId, arr); }
    arr.push(row.fromPath);
  }

  const annotationsByPath = new Map<string, { line: number; note: string }[]>();
  for (const a of db.getAnnotationsForPaths(allMemberPaths.map((p) => resolve(projectDir, p)))) {
    let arr = annotationsByPath.get(a.path);
    if (!arr) { arr = []; annotationsByPath.set(a.path, arr); }
    arr.push({ line: (a as { line?: number }).line ?? 0, note: a.note });
  }

export function buildGettingStartedBundle(
  discovery: DiscoveryResult,
  classified: ClassifiedInventory,
  syntheses: SynthesesFile,
  bundlesById: Map<string, CommunityBundle>,
  architecture: ArchitectureBundle,
  projectDir: string,
): GettingStartedBundle {
  const readme = readFileIfExists(join(projectDir, "README.md"))
    ?? readFileIfExists(join(projectDir, "README"));

  const packageManifest = readPackageManifest(projectDir);

  const sortedCommunities = [...architecture.communities].sort((a, b) => {
    const ra = architecture.communityPageRank[a.slug] ?? 0;
    const rb = architecture.communityPageRank[b.slug] ?? 0;
    return rb - ra || a.slug.localeCompare(b.slug);
  });
  const top = sortedCommunities[0];
  const topCommunity = top
    ? { slug: top.slug, name: top.name, purpose: top.purpose }
    : null;

  const cliEntryPoints = discovery.graphData.fileLevel.nodes
    .filter((n) => n.isEntryPoint && CLI_NAME_PATTERN.test(basename(n.path)))
    .sort((a, b) => a.path.localeCompare(b.path))
    .map((n) => ({ path: n.path, exports: n.exports }));

  const configFiles = readConfigFiles(projectDir);

  const originCommits = collectOriginCommits(bundlesById);

  return {
    readme,
    packageManifest,
    topCommunity,
    cliEntryPoints,
    configFiles,
    originCommits,
  };
}

