      try {
        const stat = statSync(fullPath);
        sessions.push({
          sessionId,
          jsonlPath: fullPath,
          mtime: stat.mtimeMs,
          size: stat.size,
        });
      } catch {
        // Skip files we can't stat
      }
    }
  } catch {
    // Claude project dir doesn't exist yet
  }

  // Sort by mtime descending (most recent first)
  sessions.sort((a, b) => b.mtime - a.mtime);
