export function findUsages(db: Database, symbolName: string, exact: boolean, top: number): UsageResult[] {
  const definingFileIds = new Set(
    db
      .query<{ file_id: number }, [string]>(
        "SELECT file_id FROM file_exports WHERE LOWER(name) = LOWER(?)"
      )
      .all(symbolName)
      .map((r) => r.file_id)
  );

  let rows: { id: number; snippet: string; file_id: number; chunk_index: number; start_line: number | null; path: string }[] = [];
  try {
    const ftsQuery = `"${symbolName.replace(/"/g, '""')}"`;
    rows = db
      .query<
        { id: number; snippet: string; file_id: number; chunk_index: number; start_line: number | null; path: string },
        [string, number]
      >(
        `SELECT c.id, c.snippet, c.file_id, c.chunk_index, c.start_line, f.path
         FROM fts_chunks fts
         JOIN chunks c ON c.id = fts.rowid
         JOIN files f ON f.id = c.file_id
         WHERE fts_chunks MATCH ?
         ORDER BY rank
         LIMIT ?`
      )
      .all(ftsQuery, top * 5);
  } catch {
    return [];
  }

  const pattern = exact
    ? new RegExp(`\\b${escapeRegex(symbolName)}\\b`, "i")
    : new RegExp(`\\b${escapeRegex(symbolName)}`, "i");

  const results: UsageResult[] = [];

  for (const row of rows) {
    if (definingFileIds.has(row.file_id)) continue;

    const lines = row.snippet.split("\n");
    let matchOffset = -1;
    let matchSnippet = row.snippet.slice(0, 120).trim();

    for (let i = 0; i < lines.length; i++) {
      if (pattern.test(lines[i])) {
        matchOffset = i;
        matchSnippet = lines[i].trim();
        break;
      }
    }

    const line =
      row.start_line != null && matchOffset >= 0
        ? row.start_line + matchOffset
        : row.start_line;

    results.push({ path: row.path, line, snippet: matchSnippet });
    if (results.length >= top) break;
  }

export function formatBenchmarkReport(summary: BenchmarkSummary, topK: number = 5): string {
  const lines: string[] = [];

  lines.push(`Benchmark results (${summary.total} queries, top-${topK}):`);
  lines.push(`  Recall@${topK}:      ${(summary.recallAtK * 100).toFixed(1)}%`);
  lines.push(`  MRR:            ${summary.mrr.toFixed(3)}`);
  lines.push(`  Zero-miss rate: ${(summary.zeroMissRate * 100).toFixed(1)}% (${summary.results.filter((r) => !r.hit).length} queries)`);

  // Show failures
  const failures = summary.results.filter((r) => !r.hit);
  if (failures.length > 0) {
    lines.push("\nMissed queries (no expected file in results):");
    for (const f of failures) {
      lines.push(`  "${f.query}"`);
      lines.push(`    expected: ${f.expected.join(", ")}`);
      const got = f.results.length > 0
        ? f.results.map((r) => r.path).join(", ")
        : "(no results)";
      lines.push(`    got:      ${got}`);
    }
  }

  // Show partial hits (recall < 1 but > 0)
  const partials = summary.results.filter((r) => r.hit && r.recall < 1);
  if (partials.length > 0) {
    lines.push("\nPartial matches (some expected files missing):");
    for (const p of partials) {
      lines.push(`  "${p.query}" — recall: ${(p.recall * 100).toFixed(0)}%`);
    }
  }

  return lines.join("\n");
}

