export async function indexGitHistory(
  projectDir: string,
  db: RagDB,
  options?: {
    since?: string;
    onProgress?: (msg: string, opts?: { transient?: boolean }) => void;
    threads?: number;
  }
): Promise<GitIndexResult> {
  const onProgress = options?.onProgress;
  const result: GitIndexResult = { indexed: 0, skipped: 0, total: 0 };

  const gitRoot = await findGitRoot(projectDir);
  if (!gitRoot) {
    onProgress?.("Not a git repository — skipping git history indexing");
    return result;
  }

  // Determine the range to index
  let sinceRef = options?.since;
  if (!sinceRef) {
    const lastHash = db.getLastIndexedCommit();
    if (lastHash) {
      // Check if lastHash is still a valid ancestor
      const isAncestor = await runGit(
        ["merge-base", "--is-ancestor", lastHash, "HEAD"],
        gitRoot
      );
      if (isAncestor !== null) {
        sinceRef = lastHash;
      } else {
        // Force push detected — find the fork point to minimize re-indexing.
        // Walk indexed commits oldest-to-newest and find the last one still
        // in current history. Purge everything after it.
        onProgress?.("Force push detected — finding shared history...");
        const recovery = await handleForcePush(db, gitRoot, onProgress);
        if (recovery) {
          sinceRef = recovery.hash;
          onProgress?.(`Purged ${recovery.purged} orphaned commits, resuming from ${recovery.hash.slice(0, 8)}`);
        } else {
          onProgress?.("No shared history found — rebuilding full index.");
          db.clearGitHistory();
        }
      }
    }
  }

  // Get commit log
  const logArgs = [
    "log",
    `--format=${RECORD_SEP}%H${FIELD_SEP}%an${FIELD_SEP}%ae${FIELD_SEP}%aI${FIELD_SEP}%D${FIELD_SEP}%B`,
    "--all",
  ];
  if (sinceRef) {
    logArgs.push(`${sinceRef}..HEAD`);
  }

  onProgress?.("Scanning git history...");
  const logOutput = await runGit(logArgs, gitRoot);

export async function initCommand(args: string[], getFlag: (flag: string) => string | undefined) {
  const dir = resolve(args[1] && !args[1].startsWith("--") ? args[1] : ".");
  const autoYes = args.includes("--yes") || args.includes("-y");
  const verbose = args.includes("--verbose") || args.includes("-v");
  const ideFlag = getFlag("--ide");
  const ides = ideFlag ? parseIdeFlag(ideFlag) : undefined;
  const { actions, unknownIdes } = await runSetup(dir, ides);
  if (actions.length === 0 && unknownIdes.length === 0) {
    cli.log("Already set up — nothing to do.");
  } else {
    for (const action of actions) cli.log(action);
  }

  if (unknownIdes.length > 0) {
    cli.log(`\nAdd this to your agent's MCP config (${unknownIdes.join(", ")}):\n`);
    cli.log(mcpConfigSnippet(dir));
  }

  cli.log();
  const shouldIndex = autoYes || await confirm("Index project now? [Y/n] ");
  if (shouldIndex) {
    const db = new RagDB(dir);
    const config = await loadConfig(dir);
    cli.log(`Indexing ${dir}...`);

    const ragDir = join(dir, ".mimirs");
    const statusPath = join(ragDir, "status");
    const writeStatus = (status: string) => {
      try {
        mkdirSync(ragDir, { recursive: true });
        writeFileSync(statusPath, status);
      } catch { /* best-effort */ }
    };

    let totalFiles = 0;
    let processedFiles = 0;
    let quietProgress: ReturnType<typeof createQuietProgress> | null = null;
    const startTime = Date.now();

    const result = await indexDirectory(dir, db, config, (msg, progressOpts) => {
      if (msg === "file:done") {
        processedFiles++;
        if (totalFiles > 0) {
          const pct = Math.round((processedFiles / totalFiles) * 100);
          writeStatus(`${processedFiles}/${totalFiles} files (${pct}%)`);
        }
      }

      const foundMatch = msg.match(/^Found (\d+) files to index$/);
      if (foundMatch) {
        totalFiles = parseInt(foundMatch[1], 10);
        writeStatus(`0/${totalFiles} files`);
        if (!verbose) {
          quietProgress = createQuietProgress(totalFiles);
        }
      }

      if (msg.startsWith("scanning files")) {
        writeStatus(msg);
      }

export function insertChunkBatch(
  db: Database,
  fileId: number,
  chunks: EmbeddedChunk[],
  startIndex: number
) {
  const tx = db.transaction(() => {
    for (let i = 0; i < chunks.length; i++) {
      const { snippet, embedding, entityName, chunkType, startLine, endLine, contentHash, parentId } = chunks[i];
      db.run(
        "INSERT INTO chunks (file_id, chunk_index, snippet, entity_name, chunk_type, start_line, end_line, content_hash, parent_id) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)",
        [fileId, startIndex + i, snippet, entityName ?? null, chunkType ?? null, startLine ?? null, endLine ?? null, contentHash ?? null, parentId ?? null]
      );
      const chunkId = Number(
        db.query<{ id: number }, []>("SELECT last_insert_rowid() as id").get()!.id
      );
      db.run(
        "INSERT INTO vec_chunks (chunk_id, embedding) VALUES (?, ?)",
        [chunkId, new Uint8Array(embedding.buffer)]
      );
    }
  });
  tx();
}

