export function readJSONL(
  filePath: string,
  fromOffset = 0
): { entries: JournalEntry[]; newOffset: number } {
  const stat = statSync(filePath);
  if (fromOffset >= stat.size) {
    return { entries: [], newOffset: fromOffset };
  }

  const bytesToRead = stat.size - fromOffset;
  const buf = Buffer.alloc(bytesToRead);
  const fd = openSync(filePath, "r");
  try {
    readSync(fd, buf, 0, bytesToRead, fromOffset);
  } finally {
    closeSync(fd);
  }
  const text = buf.toString("utf-8");
  const entries: JournalEntry[] = [];

  for (const line of text.split("\n")) {
    const trimmed = line.trim();
    if (!trimmed) continue;
    try {
      entries.push(JSON.parse(trimmed));
    } catch {
      // Skip malformed lines
    }
  }

  return { entries, newOffset: stat.size };
}

export function readSnapshot(wikiDir: string): PreRegenSnapshot | null {
  const path = snapshotPath(wikiDir);
  if (!existsSync(path)) return null;
  try {
    const raw = readFileSync(path, "utf-8");
    const parsed = JSON.parse(raw) as PreRegenSnapshot;
    if (parsed.version !== 1) return null;
    return parsed;
  } catch {
    return null;
  }
}

