export async function searchCommand(args: string[], getFlag: (flag: string) => string | undefined) {
  const query = args[1];
  if (!query) {
    cli.error("Usage: mimirs search <query> [--top N] [--ext .ts,.tsx] [--in src,packages/core] [--exclude tests]");
    process.exit(1);
  }

  const dir = resolve(getFlag("--dir") || ".");
  const db = new RagDB(dir);
  const config = await loadConfig(dir);
  applyEmbeddingConfig(config);
  const top = parseInt(getFlag("--top") || String(config.searchTopK), 10);
  const filter = buildCliFilter(dir, getFlag);

  const results = await search(query, db, top, 0, config.hybridWeight, config.generated, filter);

  if (results.length === 0) {
    cli.log("No results found. Has the directory been indexed?");
  } else {
    for (const r of results) {
      cli.log(`${r.score.toFixed(4)}  ${r.path}`);
      const preview = r.snippets[0]?.slice(0, 120).replace(/\n/g, " ");
      cli.log(`         ${preview}...`);
      cli.log();
    }
  }
  db.close();
}

export function searchConversation(
  db: Database,
  queryEmbedding: Float32Array,
  topK: number = 5,
  sessionId?: string
): ConversationSearchResult[] {
  // Use subquery for vector search, then JOIN for turn data
  const rows = db
    .query<
      {
        chunk_id: number;
        distance: number;
        snippet: string;
        turn_id: number;
        turn_index: number;
        session_id: string;
        timestamp: string;
        summary: string;
        tools_used: string;
        files_referenced: string;
      },
      [Uint8Array, number]
    >(
      `SELECT v.chunk_id, v.distance, cc.snippet, cc.turn_id,
              ct.turn_index, ct.session_id, ct.timestamp, ct.summary, ct.tools_used, ct.files_referenced
       FROM (SELECT chunk_id, distance FROM vec_conversation WHERE embedding MATCH ? ORDER BY distance LIMIT ?) v
       JOIN conversation_chunks cc ON cc.id = v.chunk_id
       JOIN conversation_turns ct ON ct.id = cc.turn_id`
    )
    .all(new Uint8Array(queryEmbedding.buffer), sessionId ? topK * 10 : topK * 3);

  const results: ConversationSearchResult[] = [];
  const seenTurns = new Set<number>();

  for (const row of rows) {
    if (seenTurns.has(row.turn_id)) continue;
    seenTurns.add(row.turn_id);

    if (sessionId && row.session_id !== sessionId) continue;

    results.push({
      turnId: row.turn_id,
      turnIndex: row.turn_index,
      sessionId: row.session_id,
      timestamp: row.timestamp,
      summary: row.summary || "",
      snippet: row.snippet,
      toolsUsed: JSON.parse(row.tools_used || "[]"),
      filesReferenced: JSON.parse(row.files_referenced || "[]"),
      score: 1 / (1 + row.distance),
    });

    if (results.length >= topK) break;
  }

  return results;
}

export function searchGitCommits(
  db: Database,
  queryEmbedding: Float32Array,
  topK: number = 10,
  author?: string,
  since?: string,
  until?: string,
  path?: string
): GitCommitSearchResult[] {
  const hasFilters = !!(author || since || until || path);
  const fetchLimit = hasFilters ? topK * 5 : topK * 2;

  const rows = db
    .query<
      RawRow & { commit_id: number; distance: number },
      [Uint8Array, number]
    >(
      `SELECT v.commit_id, v.distance, gc.*
       FROM (SELECT commit_id, distance FROM vec_git_commits WHERE embedding MATCH ? ORDER BY distance LIMIT ?) v
       JOIN git_commits gc ON gc.id = v.commit_id`
    )
    .all(new Uint8Array(queryEmbedding.buffer), fetchLimit);

  let results: GitCommitSearchResult[] = rows.map((row) => ({
    ...parseRow(row),
    score: 1 / (1 + row.distance),
  }));

  if (hasFilters) {
    results = applyFilters(results, author, since, until, path);
  }

  return results.slice(0, topK);
}

